map<pair<int,int>, int> DP;

int solve(int n,int maxi,vector<int> &A, vector<int> &B){
    auto itr = DP.find({n,maxi});
    if(itr != DP.end()) return itr->second;

    if(n==0){
        int ans = min(max(A[n],B[n]),maxi) - min(A[n],B[n]);
        if(ans > 0) return DP[{n,maxi}] = ans;
        else return DP[{n,maxi}] = 0;
    }

    int ans = 0;
    for(int index = min(A[n],B[n]);index<= max(A[n],B[n]) and index < maxi; index++){
        ans += solve(n-1,index,A,B);
    }       
    return DP[{n,maxi}] = ans;
}
